import { Select, SelectProps } from 'antd';
import React, { FC, useMemo } from 'react';
import { nanoid } from 'nanoid';
import classNames from 'classnames';
import { useMount } from '@spotter/app-client-toolkit';
import './index.less';
import { SptComponentProvider } from '@/components/Provider';

export interface SptSelectWithInnerLabelProps extends Omit<SelectProps, 'getPopupContainer'> {
    label: string;
}

export const SptSelectWithInnerLabel: FC<SptSelectWithInnerLabelProps> = ({
    label,
    className,
    ...restProps
}) => {
    const id = useMemo(
        () =>
            `${label.replace(/[\s"']+/, '-').toLocaleLowerCase()}-${nanoid(6).toLocaleLowerCase()}`,
        [label],
    );

    useMount(() => {
        document
            .querySelector(`.${id} .ant-select-selector`)
            ?.setAttribute('data-spotter-select-inner-label', label);
        document
            .querySelector(`.${id} .ant-select-selector .ant-select-selection-search`)
            ?.setAttribute('data-spotter-select-inner-label', label);
    });

    return (
        <SptComponentProvider>
            <Select
                filterOption={
                    restProps.filterOption == false
                        ? false
                        : (inputValue, option) => {
                              if (
                                  restProps.filterOption &&
                                  typeof restProps.filterOption === 'function'
                              ) {
                                  return restProps.filterOption(inputValue, {
                                      ...option,
                                      label: option?.title,
                                  });
                              }
                              return !!(
                                  option?.title
                                      ?.toString()
                                      .toLowerCase()
                                      .includes(inputValue.toLowerCase()) ||
                                  option?.label
                                      ?.toString()
                                      .toLowerCase()
                                      .includes(inputValue.toLowerCase()) ||
                                  option?.value
                                      ?.toString()
                                      .toLowerCase()
                                      .includes(inputValue.toLowerCase())
                              );
                          }
                }
                // 使用pro-components的过滤逻辑
                {...restProps}
                className={classNames('spotter-select-with-inner-label', className, id)}
            />
        </SptComponentProvider>
    );
};
